parameters.script:
module.exports = async function({ input }) {
  const rows = Array.isArray(input && input.rows) ? input.rows : [];
  const escapeHtml = (value) => String(value == null ? '' : value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
  const phoneHref = (value) => String(value == null ? '' : value).replace(/[^+0-9]/g, '');
  const tableRows = rows.map((row, index) => '<tr>' +
    '<td style="padding:8px 10px;border-bottom:1px solid #e8e1d0;color:#666;">' + (index + 1) + '</td>' +
    '<td style="padding:8px 10px;border-bottom:1px solid #e8e1d0;font-family:monospace;font-size:12px;">' + escapeHtml(row.id) + '</td>' +
    '<td style="padding:8px 10px;border-bottom:1px solid #e8e1d0;font-weight:600;">' + escapeHtml(row.company_name) + '</td>' +
    '<td style="padding:8px 10px;border-bottom:1px solid #e8e1d0;"><a style="color:#9c7a1f;" href="tel:' + escapeHtml(phoneHref(row.phone)) + '">' + escapeHtml(row.phone) + '</a></td>' +
    '</tr>').join('');
  const emptyRow = '<tr><td colspan="4" style="padding:18px;color:#666;text-align:center;">No leads without a website and with a telephone number were found.</td></tr>';
  const html = '<div style="font-family:Arial,Helvetica,sans-serif;background:#f7f5f0;padding:24px;">' +
    '<table width="100%" style="max-width:980px;margin:0 auto;background:#fff;border:1px solid #e8e1d0;border-radius:8px;border-collapse:separate;border-spacing:0;overflow:hidden;">' +
    '<tr><td colspan="4" style="background:#0a0a0a;padding:22px 28px;"><span style="color:#d4af37;font-size:20px;font-weight:bold;letter-spacing:1px;">DEE EMPIRE</span><span style="color:#fff;font-size:12px;float:right;margin-top:6px;">NO-WEBSITE PHONE LEADS</span></td></tr>' +
    '<tr><td colspan="4" style="padding:22px 28px;"><h2 style="margin:0 0 6px;">' + rows.length + ' leads without a website and with phone</h2><p style="margin:0;color:#666;">Database snapshot generated at ' + escapeHtml(new Date().toISOString()) + '</p></td></tr>' +
    '<tr style="background:#fbf7ec;"><th align="left" style="padding:9px 10px;color:#9c7a1f;">#</th><th align="left" style="padding:9px 10px;color:#9c7a1f;">Lead ID</th><th align="left" style="padding:9px 10px;color:#9c7a1f;">Company</th><th align="left" style="padding:9px 10px;color:#9c7a1f;">Telephone</th></tr>' +
    (tableRows || emptyRow) +
    '<tr><td colspan="4" style="background:#0a0a0a;color:#cfcfcf;padding:14px 28px;text-align:center;font-size:11px;">Dee Empire automated CRM report</td></tr>' +
    '</table></div>';
  return { html, count: rows.length, subject: 'Dee Empire CRM: ' + rows.length + ' no-website leads with phone' };
};
